const body = $json.body ?? $json;
const technician = String(body.technician ?? '').trim();
const items = Array.isArray(body.items) ? body.items : [];
if (!technician) throw new Error('technician is required');
if (!items.length) throw new Error('at least one item is required');
const timestamp = body.timestamp || new Date().toISOString();
const requestId = body.request_id || `fallback-${Date.now()}`;
const lines = items.map((item, index) => `${index + 1}. ${item.item_name} | ${item.item_id} | qty=${item.quantity} | unit=${item.unit} | category=${item.category}`);
return [{ json: { request_id: requestId, timestamp, technician, job: String(body.job ?? ''), item_count: items.length, items, email_subject: `Inventory Checkout ${technician} ${timestamp}`, email_text: `Inventory checkout submitted.

Request ID: ${requestId}
Timestamp: ${timestamp}
Technician: ${technician}
Job: ${String(body.job ?? '') || 'N/A'}
Item Count: ${items.length}

Items:
${lines.join('
')}` } }];
